import { EMPTY_INPUT, type GameSessionState } from '../game/types'
import { EMPTY_UPGRADE_LEVELS } from '../services/shopService'

type GameStoreListener = (state: GameSessionState) => void

const initialState: GameSessionState = {
  status: 'idle',
  score: 0,
  lives: 3,
  stage: 1,
  highScore: 0,
  activeUpgrades: [],
  upgradeLevels: { ...EMPTY_UPGRADE_LEVELS },
  activePowerUps: [],
  activeDrops: [],
  bossEncounter: {
    active: false,
    bossId: null,
    stage: null,
    attempt: 0,
    startedAtMs: null,
    endedAtMs: null,
    outcome: 'none',
    damageTaken: 0,
    health: 0,
    maxHealth: 0
  },
  progressionProfile: {
    highestUnlockedStage: 1,
    totalRuns: 0,
    lastAttemptedStage: null,
    lastCompletedStage: null,
    interruptedRun: null
  },
  runModifierOffer: null,
  input: EMPTY_INPUT
}

class GameStore {
  private state: GameSessionState = initialState
  private listeners = new Set<GameStoreListener>()

  getState(): GameSessionState {
    return this.state
  }

  setState(partial: Partial<GameSessionState>): void {
    this.state = {
      ...this.state,
      ...partial
    }

    this.listeners.forEach((listener) => listener(this.state))
  }

  reset(): void {
    this.state = {
      ...initialState,
      highScore: this.state.highScore,
      progressionProfile: this.state.progressionProfile,
      activeDrops: []
    }
    this.listeners.forEach((listener) => listener(this.state))
  }

  subscribe(listener: GameStoreListener): () => void {
    this.listeners.add(listener)
    listener(this.state)

    return () => {
      this.listeners.delete(listener)
    }
  }
}

export const gameStore = new GameStore()

import type { BossAttackPatternId } from '../entities/boss'

export type BossMovementModel = 'drift' | 'zigzag' | 'sweep' | 'dive' | 'chaotic'
export type BossFeedbackPreset = 'ember' | 'volt' | 'frost' | 'nova' | 'void'

export type BossProfile = {
  stage: number
  attackPatternSequence: BossAttackPatternId[]
  telegraphMs: number
  movementModel: BossMovementModel
  feedbackPreset: BossFeedbackPreset
}

const PROFILES: BossProfile[] = [
  {
    stage: 1,
    attackPatternSequence: ['burst-3', 'targeted-2'],
    telegraphMs: 1450,
    movementModel: 'drift',
    feedbackPreset: 'ember'
  },
  {
    stage: 2,
    attackPatternSequence: ['line-5', 'burst-3', 'targeted-2'],
    telegraphMs: 1350,
    movementModel: 'zigzag',
    feedbackPreset: 'volt'
  },
  {
    stage: 3,
    attackPatternSequence: ['targeted-2', 'line-5', 'burst-3'],
    telegraphMs: 1250,
    movementModel: 'sweep',
    feedbackPreset: 'frost'
  },
  {
    stage: 4,
    attackPatternSequence: ['line-5', 'targeted-2', 'burst-3'],
    telegraphMs: 1150,
    movementModel: 'dive',
    feedbackPreset: 'nova'
  },
  {
    stage: 5,
    attackPatternSequence: ['targeted-2', 'burst-3', 'line-5', 'burst-3'],
    telegraphMs: 1050,
    movementModel: 'chaotic',
    feedbackPreset: 'void'
  }
]

const DEFAULT_PROFILE: BossProfile = {
  stage: 0,
  attackPatternSequence: ['line-5', 'targeted-2', 'burst-3'],
  telegraphMs: 1000,
  movementModel: 'chaotic',
  feedbackPreset: 'void'
}

export function getBossProfileForStage(stage: number, attempt = 1): BossProfile {
  const base = PROFILES.find((item) => item.stage === stage)
  if (!base) {
    return {
      ...DEFAULT_PROFILE,
      stage
    }
  }

  const shift = Math.abs(attempt - 1) % base.attackPatternSequence.length
  const rotated = [...base.attackPatternSequence.slice(shift), ...base.attackPatternSequence.slice(0, shift)]

  return {
    ...base,
    attackPatternSequence: rotated,
    telegraphMs: Math.max(900, base.telegraphMs - Math.min(3, attempt - 1) * 50)
  }
}

import { getStageConfig, type StageConfig } from '../config/stages'
import { isBossStage } from '../config/gameplay'
import type { UpgradeLevels } from '../../services/shopService'
import { generateRunModifierOffer } from './runModifierSystem'

export type ProgressionResult = {
  enterShop: boolean
  enterBossFight: boolean
  nextStage: number
  nextStageConfig: StageConfig
}

export function evaluateStageProgression(
  currentStage: number,
  enemiesRemaining: number,
  bossActive = false,
  bossDefeated = false
): ProgressionResult {
  if (enemiesRemaining > 0) {
    return {
      enterShop: false,
      enterBossFight: false,
      nextStage: currentStage,
      nextStageConfig: getStageConfig(currentStage)
    }
  }

  const bossStage = isBossStage(currentStage)

  if (!bossStage) {
    const nextStage = currentStage + 1
    return {
      enterShop: true,
      enterBossFight: false,
      nextStage,
      nextStageConfig: getStageConfig(nextStage)
    }
  }

  if (!bossActive) {
    return {
      enterShop: false,
      enterBossFight: true,
      nextStage: currentStage,
      nextStageConfig: getStageConfig(currentStage)
    }
  }

  if (!bossDefeated) {
    return {
      enterShop: false,
      enterBossFight: false,
      nextStage: currentStage,
      nextStageConfig: getStageConfig(currentStage)
    }
  }

  const nextStage = currentStage + 1

  return {
    enterShop: true,
    enterBossFight: false,
    nextStage,
    nextStageConfig: getStageConfig(nextStage)
  }
}

export function createShopRunModifierOffer(input: {
  runId: string
  runSeed: string
  stageNumber: number
  upgradeLevels: UpgradeLevels
}) {
  return generateRunModifierOffer({
    runId: input.runId,
    stageNumber: input.stageNumber,
    runSeed: input.runSeed,
    upgradeLevels: input.upgradeLevels
  })
}

import { saveLocalHighscore } from '../services/highscoreService'
import { logTelemetryEvent } from '../lib/telemetry'
import {
  getPersistedProgressProfile,
  savePersistedProgressProfile
} from '../services/shopPersistenceService'
import type { UpgradeLevels } from '../services/shopService'
import { getCycleIndex, isBossStage } from './config/gameplay'
import { createEnemyGrid } from './entities/enemy'
import { clampActiveDropsByStage } from './config/performance'
import type { RareDropEntity } from './entities/dropItem'
import { createPlayer, movePlayer, tickPlayer, tryConsumeShot, type PlayerEntity } from './entities/player'
import {
  createHomingMissileProjectile,
  createLaserProjectile,
  createPlayerProjectile,
  steerHomingProjectiles,
  stepProjectiles,
  type ProjectileEntity
} from './entities/projectile'
import { createInputManager } from './input/inputManager'
import { createGameLoop, type GameLoopController } from './loop'
import { gameStore } from '../state/gameStore'
import {
  checkEnemyReachedPlayerLine,
  resolveBossProjectileCollisions,
  resolvePlayerDropCollisions,
  resolveEnemyProjectileHitsPlayer,
  resolvePlayerProjectileCollisions
} from './systems/collisionSystem'
import { emitBossProjectiles } from './systems/bossAttackSystem'
import { spawnBossForWave, tickBoss } from './systems/bossSystem'
import { removeExpiredDrops, resolveCollectedSpecialShot, stepDrops } from './systems/dropSystem'
import { createShopRunModifierOffer, evaluateStageProgression } from './systems/progressionSystem'
import { addOrRefreshPowerUp, getActiveWeaponPowerUp, removeExpiredPowerUps } from './systems/powerUpSystem'
import { updateScoreAndLives } from './systems/scoreLivesSystem'
import { applyPlayerUpgrades } from './systems/upgradeSystem'
import {
  applyWaveEnemies,
  createDropsFromDefeatedEnemies,
  emitEnemyProjectiles,
  stepEnemies,
  type WaveState
} from './systems/waveSystem'

let context: CanvasRenderingContext2D | null = null
let loopController: GameLoopController | null = null
const inputManager = createInputManager()
let player: PlayerEntity | null = null
let wave: WaveState = {
  stage: 1,
  enemies: createEnemyGrid(1),
  boss: null,
  direction: 1
}
let projectiles: ProjectileEntity[] = []
let activeDrops: RareDropEntity[] = []
let pendingStage: number | null = null
let currentRunId = 'run-0'
let currentRunSeed = 'seed-0'
let bossEncounterStartLives: number | null = null

type BossEncounterSnapshot = ReturnType<typeof gameStore.getState>['bossEncounter']

function getBossEncounterAttemptForStage(stage: number): number {
  const encounter = gameStore.getState().bossEncounter
  if (encounter.stage === stage) {
    return encounter.attempt + 1
  }

  return 1
}

function updateBossEncounterFromWave(partial?: Partial<BossEncounterSnapshot>): void {
  const state = gameStore.getState()
  const existing = state.bossEncounter
  const nextHealth = wave.boss?.health ?? 0
  const nextMaxHealth = wave.boss?.maxHealth ?? 0
  const livesBase = bossEncounterStartLives ?? state.lives

  gameStore.setState({
    bossEncounter: {
      ...existing,
      active: Boolean(wave.boss),
      bossId: wave.boss?.id ?? null,
      stage: wave.boss?.stage ?? existing.stage,
      health: nextHealth,
      maxHealth: nextMaxHealth,
      damageTaken: wave.boss ? Math.max(existing.damageTaken, livesBase - state.lives) : existing.damageTaken,
      ...partial
    }
  })
}

function startBossEncounter(nowMs: number): void {
  const state = gameStore.getState()
  bossEncounterStartLives = state.lives
  updateBossEncounterFromWave({
    stage: wave.stage,
    attempt: getBossEncounterAttemptForStage(wave.stage),
    startedAtMs: nowMs,
    endedAtMs: null,
    outcome: 'in-progress',
    damageTaken: 0
  })
}

function handleBossVictory(nowMs: number): void {
  const state = gameStore.getState()
  const livesBase = bossEncounterStartLives ?? state.lives

  gameStore.setState({
    bossEncounter: {
      ...state.bossEncounter,
      active: false,
      endedAtMs: nowMs,
      outcome: 'victory',
      bossId: state.bossEncounter.bossId,
      health: 0,
      maxHealth: state.bossEncounter.maxHealth,
      damageTaken: Math.max(state.bossEncounter.damageTaken, livesBase - state.lives)
    }
  })
  bossEncounterStartLives = null
}

function handleBossPlayerDefeat(nowMs: number): void {
  const state = gameStore.getState()
  const livesBase = bossEncounterStartLives ?? state.lives

  gameStore.setState({
    bossEncounter: {
      ...state.bossEncounter,
      active: false,
      endedAtMs: nowMs,
      outcome: 'defeat',
      damageTaken: Math.max(state.bossEncounter.damageTaken, livesBase - state.lives)
    }
  })
  bossEncounterStartLives = null
}

function syncStore(): void {
  const state = gameStore.getState()
  gameStore.setState({
    score: state.score,
    lives: state.lives,
    stage: wave.stage,
    bossEncounter: {
      ...state.bossEncounter,
      active: Boolean(wave.boss),
      bossId: wave.boss?.id ?? null,
      stage: wave.boss?.stage ?? state.bossEncounter.stage,
      health: wave.boss?.health ?? 0,
      maxHealth: wave.boss?.maxHealth ?? 0
    },
    activeDrops: activeDrops.map((drop) => ({
      id: drop.id,
      x: drop.x,
      y: drop.y,
      width: drop.width,
      height: drop.height,
      grantedShotType: drop.grantedShotType,
      expiresAtMs: drop.expiresAtMs
    })),
    input: inputManager.readInput()
  })
}

function resetRoundState(canvas: HTMLCanvasElement, stage = 1): void {
  player = createPlayer(canvas.width, canvas.height)
  wave = {
    stage,
    enemies: createEnemyGrid(stage),
    boss: null,
    direction: 1
  }
  projectiles = []
  activeDrops = []
  pendingStage = null
  currentRunId = 'run-0'
  currentRunSeed = 'seed-0'
  bossEncounterStartLives = null
}

function update(deltaSeconds: number): void {
  if (!context || !player) {
    return
  }

  const state = gameStore.getState()
  if (state.status !== 'running') {
    return
  }

  const input = inputManager.readInput()
  const nowMs = Date.now()
  if (input.pause) {
    pauseGame()
    return
  }

  let activePowerUps = removeExpiredPowerUps(state.activePowerUps, nowMs)
  activeDrops = removeExpiredDrops(activeDrops, nowMs)
  activeDrops = stepDrops(activeDrops, deltaSeconds, context.canvas.height)

  player = tickPlayer(player, deltaSeconds)
  player = movePlayer(player, input.horizontal, deltaSeconds, context.canvas.width)

  if (input.fire) {
    const [nextPlayer, shouldShoot] = tryConsumeShot(player)
    player = nextPlayer

    if (shouldShoot) {
      const weaponPowerUp = getActiveWeaponPowerUp(activePowerUps)
      if (weaponPowerUp === 'laser') {
        projectiles.push(createLaserProjectile(player.x + player.width / 2 - 4, player.y - 12))
      } else if (weaponPowerUp === 'homing-missile') {
        projectiles.push(createHomingMissileProjectile(player.x + player.width / 2 - 3, player.y - 12))
      } else {
        projectiles.push(createPlayerProjectile(player.x + player.width / 2 - 2, player.y - 10))
      }
    }
  }

  const targetX = wave.boss ? wave.boss.x + wave.boss.width / 2 : wave.enemies[0]?.x ?? null
  projectiles = steerHomingProjectiles(projectiles, targetX, deltaSeconds)
  wave = stepEnemies(wave, deltaSeconds, context.canvas.width)
  wave = tickBoss(wave, deltaSeconds, context.canvas.width)
  projectiles = stepProjectiles(projectiles, deltaSeconds, context.canvas.height)

  const enemyShotsUpdate = emitEnemyProjectiles(wave, projectiles, player.x + player.width / 2)
  wave = enemyShotsUpdate.wave
  projectiles = enemyShotsUpdate.projectiles

  const bossShotResult = emitBossProjectiles(wave, projectiles, player.x + player.width / 2)
  wave = bossShotResult.wave
  projectiles = bossShotResult.projectiles

  const collisionResult = resolvePlayerProjectileCollisions(wave.enemies, projectiles)
  if (collisionResult.defeatedEnemies.length > 0) {
    const spawnedDrops = createDropsFromDefeatedEnemies(collisionResult.defeatedEnemies, nowMs)

    if (spawnedDrops.length > 0) {
      const merged = [...activeDrops, ...spawnedDrops]
      const allowedCount = clampActiveDropsByStage(wave.stage, merged.length)
      activeDrops = merged.slice(-allowedCount)
    }
  }
  wave = applyWaveEnemies(wave, collisionResult.enemies)
  projectiles = collisionResult.projectiles

  const bossBeforeCollision = wave.boss
  const bossCollisionResult = resolveBossProjectileCollisions(wave.boss, projectiles)
  wave = {
    ...wave,
    boss: bossCollisionResult.boss
  }
  projectiles = bossCollisionResult.projectiles


