    setTelemetryConsent(nextSettings.telemetryConsent)
    void saveSettings(nextSettings)
  }

  const handleResumeInterruptedRun = () => {
    setShowInterruptedRunPrompt(false)

    if (gameStore.getState().status === 'paused') {
      resumeGame()
      return
